export type Cell = [number, number];

const SURVIVAL_NEIGHBOR_COUNTS = [2, 3];

function isNeighbor(a: Cell, b: Cell): boolean {
  const [ax, ay] = a;
  const [bx, by] = b;
  if (ax === bx && ay === by) return false;
  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
}

function countLiveNeighbors(cell: Cell, cells: Cell[]): number {
  return cells.filter((other) => isNeighbor(cell, other)).length;
}

function survives(cell: Cell, cells: Cell[]): boolean {
  return SURVIVAL_NEIGHBOR_COUNTS.includes(countLiveNeighbors(cell, cells));
}

export function nextGeneration(cells: Cell[]): Cell[] {
  return cells.filter((cell) => survives(cell, cells));
}

